const crypto = require('crypto');
const input = $input.first().json;
const headers = input.headers ?? {};
const signature = headers['x-line-signature'] ?? headers['X-Line-Signature'];
const secret = $env.LINE_CHANNEL_SECRET;
if (!secret || !signature) throw new Error('Missing LINE signature configuration');
const rawBody = typeof input.body === 'string' ? input.body : (typeof input.rawBody === 'string' ? input.rawBody : JSON.stringify(input.body ?? {}));
const expected = crypto.createHmac('sha256', secret).update(rawBody, 'utf8').digest('base64');
const actualBuffer = Buffer.from(signature);
const expectedBuffer = Buffer.from(expected);
if (actualBuffer.length !== expectedBuffer.length || !crypto.timingSafeEqual(actualBuffer, expectedBuffer)) throw new Error('Invalid LINE webhook signature');
const body = typeof input.body === 'string' ? JSON.parse(input.body) : (input.body ?? {});
const events = (Array.isArray(body.events) ? body.events : []).filter(event => event.replyToken && event.source?.userId);
const processed = [];
for (const event of events) {
  const postbackData = event.type === 'postback' ? (event.postback?.data ?? '') : '';
  const messageText = event.type === 'message' && event.message?.type === 'text' ? (event.message.text ?? '') : postbackData;
  const trimmedText = messageText.trim();
  const match = /^crawl_status:(\d+)$/.exec(postbackData);
  let intent = 'onboarding';
  let taskId = null;
  if (match || trimmedText === '查詢進度') {
    intent = 'status_query';
    taskId = match ? match[1] : null;
  } else if (trimmedText === '風評查詢') {
    intent = 'crawl_query';
  } else if (event.type === 'follow') {
    intent = 'onboarding';
  }
  processed.push({ json: {
    lineUserId: event.source.userId, replyToken: event.replyToken, messageText,
    webhookEventId: event.webhookEventId ?? null, isRedelivery: event.deliveryContext?.isRedelivery ?? false,
    intent, taskId
  }});
}
return processed;

const event = $('Verify LINE Signature and Parse Intent').item.json;
const status = $json ?? {};
const failedRequest = Boolean(status.error || status.message?.error || (Number(status.statusCode) >= 400));
const taskId = status.task_id ?? event.taskId ?? null;
const state = failedRequest ? 'not_found' : (status.status ?? 'pending');
const platforms = Array.isArray(status.platform_results) ? status.platform_results : [];
const labels = { ptt: 'PTT', google_maps: 'Google Maps', threads: 'Threads' };
const progress = platforms.length ? '\n' + platforms.map(p => `${labels[p.platform] ?? p.platform}：${p.status}`).join('\n') : '';
const quickReply = taskId ? { items: [{ type: 'action', action: { type: 'postback', label: '查詢進度', data: `crawl_status:${taskId}`, displayText: '查詢進度' } }] } : undefined;
let text;
let reportReady = false;
if (state === 'completed' || state === 'partial_success') {
  reportReady = true;
  text = `任務 ${taskId} 已完成：找到 ${Number(status.articles_found ?? 0)} 篇內容、${Number(status.comments_found ?? 0)} 則留言。`;
} else if (state === 'failed' || state === 'timeout' || state === 'cancelled') {
  text = `任務 ${taskId ?? ''} 執行失敗，請稍後重新查詢。${status.error_message ? `\n${String(status.error_message).slice(0, 300)}` : ''}`;
} else if (state === 'not_found') {
  text = '找不到可查詢的風評任務，請先重新提出店家風評查詢。';
} else {
  text = `任務 ${taskId} 目前為 ${state}，系統仍在背景處理。${progress}`;
}
const message = { type: 'text', text };
if (!reportReady && quickReply) message.quickReply = quickReply;
return [{ json: {
  replyToken: event.replyToken, lineUserId: event.lineUserId, taskId, state, reportReady,
  messages: [message], noticeMessages: reportReady ? [message] : [],
  reportPayload: { line_user_id: event.lineUserId, business_name: status.business_name ?? null, message_text: '查詢進度', refresh: false }
}}];

const request = $('Format Crawl Status Response').item.json;
const backend = $json ?? {};
const valid = !backend.error && !(Number(backend.statusCode) >= 400) && Array.isArray(backend.line_messages) && backend.line_messages.length;
const messages = valid ? [...request.noticeMessages, ...backend.line_messages].slice(0, 5) : [{ type: 'text', text: '爬蟲已完成，但報告暫時無法產生，請稍後再查詢。' }];
return [{ json: { replyToken: request.replyToken, messages } }];

const event = $('Verify LINE Signature and Parse Intent').item.json;
const recognition = $('Identify Client and Business').item.json;
return [{ json: {
  replyToken: event.replyToken, lineUserId: event.lineUserId,
  reputationCrawlerPayload: { line_user_id: event.lineUserId, business_name: recognition.business_name, webhook_event_id: event.webhookEventId }
}}];

const request = $('Prepare Crawler Trigger Payload').item.json;
const created = $json ?? {};
const taskId = created.task_id ?? null;
const canRun = Boolean(taskId) && !created.error && !(Number(created.statusCode) >= 400);
const message = canRun ? {
  type: 'text', text: '已受理店家風評查詢，系統正在背景處理。完成後請點選「查詢進度」。',
  quickReply: { items: [{ type: 'action', action: { type: 'postback', label: '查詢進度', data: `crawl_status:${taskId}`, displayText: '查詢進度' } }] }
} : { type: 'text', text: '目前無法建立風評查詢任務，請稍後再試。' };
return [{ json: { replyToken: request.replyToken, taskId, canRun, messages: [message] } }];

const event = $('Verify LINE Signature and Parse Intent').item.json;
const recognition = $('Identify Client and Business').item.json;
const displayName = recognition.branch_name ? `${recognition.business_name}｜${recognition.branch_name}` : recognition.business_name;
const message = {
  type: 'text',
  text: `🎉 恭喜！您的店家「${displayName}」已完成註冊綁定。\n\n您可以隨時點選選單中的「風評查詢」進行聲譽監測。`
};
return [{ json: { replyToken: event.replyToken, messages: [message] } }];

const event = $('Verify LINE Signature and Parse Intent').item.json;
const recognition = $('Identify Client and Business').item.json;
const messages = recognition.registration_flex_message || [{
  type: 'text',
  text: '您目前尚未綁定任何店家，請進行註冊。'
}];
return [{ json: { replyToken: event.replyToken, messages } }];

